sc_cat_item_producer.script:
// 1. Log the exact backend choice value to the system log for verification
gs.info("EMERGENCY DEBUG - Raw Choice Value Submitted: " + producer.u_assistance_type.toString());

var assignedGroup = '';
var assistanceType = producer.u_assistance_type.toString();

// 2. Route assignment groups by handling both the backend value keys and the exact portal text labels
if (assistanceType === 'temporary_housing' || assistanceType === 'Temporary Housing') {
    assignedGroup = 'Disaster Housing Team';
    assistanceType = 'temporary_housing'; // Normalize it to the correct backend choice key

} else if (assistanceType === 'emergency_funding' || assistanceType === 'Emergency Funding' || assistanceType === 'Financial Assistance') {
    assignedGroup = 'Disaster Finance Team';
    assistanceType = 'emergency_funding'; // Normalize it to the correct backend choice key

} else if (assistanceType === 'food_medical_supplies' || assistanceType === 'Food & Supplies' || assistanceType === 'Medical Assistance' || assistanceType === 'Food/Medical Supplies') {
    assignedGroup = 'Disaster Logistics Team'; 
    assistanceType = 'food_medical_supplies'; // Normalize it to the correct backend choice key

} else {
    // Catch-all fallback group for any other variant text
    assignedGroup = 'Disaster Assistance Team'; 
}

// 3. Update your payload mapping to pass the newly normalized value
var requestBody = {
    name: producer.u_citizen_name.toString(),
    email: producer.u_citizen_email.toString(),
    location: producer.u_physical_location.toString(),
    assistance_type: assistanceType, // This now passes the perfectly formatted choice value key
    assignment_group_name: assignedGroup
};


try {
    var sm = new sn_ws.RESTMessageV2();
    sm.setEndpoint(gs.getProperty('glide.servlet.uri') + 'api/x_1834272_emergenc/public_incident_intake/submit_request');
    sm.setHttpMethod('POST');
    sm.setRequestHeader("Content-Type", "application/json");
    sm.setRequestBody(JSON.stringify(requestBody));

    var apiResponse = sm.execute();
    var responseBody = apiResponse.getBody();
    var parsedData = JSON.parse(responseBody);

    if (parsedData.success || parsedData.result) {
        var redirectUrl = "sp?id=disaster_status_lookup&name=" + encodeURIComponent(requestBody.name) + "&email=" + encodeURIComponent(requestBody.email) + "&success=true";
        producer.url_redirect = redirectUrl;
        producer.nocreate = true; 
    } else {
        gs.addErrorMessage("Submission failed at the database layer.");
    }
} catch (ex) {
    gs.addErrorMessage("System integration routing error: " + ex.message);
}
